CREATE DICTIONARY IF NOT EXISTS gl_project_traversal_paths_dict (
    id Int64,
    traversal_path String
)
PRIMARY KEY id
SOURCE(CLICKHOUSE(USER 'default' QUERY $q$SELECT id, traversal_path FROM (SELECT id, argMax(traversal_path, _version) AS traversal_path FROM `default`.gl_project GROUP BY id HAVING argMax(_deleted, _version) = false)$q$))
LIFETIME(MIN 60 MAX 300)
LAYOUT(HASHED());

CREATE DICTIONARY IF NOT EXISTS gl_group_traversal_paths_dict (
    id Int64,
    traversal_path String
)
PRIMARY KEY id
SOURCE(CLICKHOUSE(USER 'default' QUERY $q$SELECT id, traversal_path FROM (SELECT id, argMax(traversal_path, _version) AS traversal_path FROM `default`.gl_group GROUP BY id HAVING argMax(_deleted, _version) = false)$q$))
LIFETIME(MIN 60 MAX 300)
LAYOUT(HASHED());

CREATE TABLE IF NOT EXISTS gkg_column_stats (
    table_name LowCardinality(String),
    column_name LowCardinality(String),
    partition_key String,
    value String,
    row_count AggregateFunction(uniq, Int64)
) ENGINE = AggregatingMergeTree
ORDER BY (table_name, column_name, partition_key, value);

CREATE TABLE IF NOT EXISTS gkg_histogram_stats (
    table_name LowCardinality(String),
    column_name LowCardinality(String),
    partition_key String,
    value String,
    row_count AggregateFunction(uniq, Int64),
    min_value SimpleAggregateFunction(min, String),
    max_value SimpleAggregateFunction(max, String)
) ENGINE = AggregatingMergeTree
ORDER BY (table_name, column_name, partition_key, value);

CREATE TABLE IF NOT EXISTS gkg_token_stats (
    table_name LowCardinality(String),
    column_name LowCardinality(String),
    partition_key String,
    token String,
    row_count AggregateFunction(uniq, Int64)
) ENGINE = AggregatingMergeTree
ORDER BY (table_name, column_name, partition_key, token);

CREATE DICTIONARY IF NOT EXISTS gkg_column_stats_dict (
    table_name String,
    column_name String,
    partition_key String,
    value String,
    row_count UInt64
)
PRIMARY KEY table_name, column_name, partition_key, value
SOURCE(CLICKHOUSE(USER 'default' QUERY $q$SELECT table_name, column_name, partition_key, value, uniqMerge(row_count) AS row_count FROM `default`.gkg_column_stats GROUP BY table_name, column_name, partition_key, value$q$))
LIFETIME(MIN 120 MAX 300)
LAYOUT(COMPLEX_KEY_HASHED());

CREATE MATERIALIZED VIEW IF NOT EXISTS gkg_stats_mv_gl_branch
TO gkg_column_stats
AS SELECT toLowCardinality('gl_branch') AS table_name, toLowCardinality(col.1) AS column_name, traversal_path AS partition_key, col.2 AS value, uniqState(id) AS row_count FROM gl_branch ARRAY JOIN [('is_default', toString(ifNull(is_default, '')))] AS col GROUP BY table_name, column_name, partition_key, value;

CREATE MATERIALIZED VIEW IF NOT EXISTS gkg_hist_mv_gl_branch
TO gkg_histogram_stats
AS SELECT toLowCardinality('gl_branch') AS table_name, toLowCardinality(col.1) AS column_name, traversal_path AS partition_key, col.2 AS value, uniqState(id) AS row_count, col.2 AS min_value, col.2 AS max_value FROM gl_branch ARRAY JOIN [('id', toString(ifNull(id, ''))), ('project_id', toString(ifNull(project_id, '')))] AS col GROUP BY table_name, column_name, partition_key, value;

CREATE MATERIALIZED VIEW IF NOT EXISTS gkg_token_mv_gl_branch
TO gkg_token_stats
AS SELECT toLowCardinality('gl_branch') AS table_name, toLowCardinality(col.1) AS column_name, traversal_path AS partition_key, col.2 AS token, uniqState(id) AS row_count FROM gl_branch ARRAY JOIN [('name', toString(ifNull(name, '')))] AS col GROUP BY table_name, column_name, partition_key, token;

