AS SELECT toLowCardinality('gl_security_scan') AS table_name, toLowCardinality(col.1) AS column_name, traversal_path AS partition_key, col.2 AS value, uniqState(id) AS row_count, col.2 AS min_value, col.2 AS max_value FROM gl_security_scan ARRAY JOIN [('id', toString(ifNull(id, ''))), ('created_at', toString(ifNull(created_at, ''))), ('updated_at', toString(ifNull(updated_at, ''))), ('project_id', toString(ifNull(project_id, ''))), ('pipeline_id', toString(ifNull(pipeline_id, ''))), ('build_id', toString(ifNull(build_id, '')))] AS col GROUP BY table_name, column_name, partition_key, value;

